   116|async function githubFetch(path, options = {}) {
   117|  const url = path.startsWith('http') ? path : `${API}${path}`;
   118|  const method = (options.method || 'GET').toUpperCase();
   119|  const res = await fetch(url, {
   120|    ...options,
   121|    headers: {
   122|      Authorization: `Bearer ${GITHUB_TOKEN}`,
   123|      Accept: 'application/vnd.github+json',
   124|      'Content-Type': 'application/json',
   125|      'X-GitHub-Api-Version': '2022-11-28',
   126|      ...options.headers,
   127|    },
   128|  });
   129|
   130|  if (!res.ok && !(res.status === 404 && method === 'GET')) {
   131|    const text = await res.text();
   132|    throw new Error(`GitHub API ${method} ${path} ${res.status} ${res.statusText}: ${text.slice(0, 800)}`);
   133|  }
   134|  if (res.status === 404) return null;
   135|  return res.json();
