   145|  if (!defaultRef) throw new Error('Cannot find default branch');
   146|
   147|  await githubFetch(`/repos/${REPO}/git/refs`, {
   148|    method: 'POST',
   149|    body: JSON.stringify({ ref: `refs/heads/${BRANCH}`, sha: defaultRef.object.sha }),
