   160|  if (tree?.tree) {
   161|    for (const item of tree.tree) {
   162|      if (item.type === 'blob') {
   163|        files.set(item.path, item.sha);
   164|      }
   165|    }
   166|  }
   167|  return { treeSha: commit.tree.sha, files };
