    72|  let body: string;
    73|  try {
    74|    body = JSON.stringify(payload);
    75|  } catch (error) {
    76|    return JSON.stringify(buildMinimalOwnerEnvelope(payload, error));
    77|  }
    78|
    79|  if (body.length <= OWNER_ONLY_MAX_RESPONSE_BYTES) {
    80|    return body;
